/* ==========================================================================
   LUFFY DARKEN THEME - PERFECT EDITION (750+ lines)
   Full background coverage, dark glass panels, Luffy light blue accents
   ========================================================================== */

/* ---------- 1. FORCE BACKGROUND IMAGE ON EVERYTHING ---------- */
html, body, #app-mount, .appMount-3, .theme-dark, .layers, .layer, .container {
  background: url('https://raw.githubusercontent.com/a67680293-sys/Revenge-theme/main/66ff8b8e6fe1d286aa44bab423133458.jpg') fixed center/cover no-repeat !important;
  background-color: #0a0a0c !important;
}

/* ---------- 2. MAKE EVERY UI PANEL DARK & SLIGHTLY TRANSLUCENT ---------- */
/* This lets the background image show through while keeping text readable */
[class*="guilds"], [class*="channels"], [class*="members"], [class*="panels"],
[class*="sidebar"], [class*="container"], [class*="wrapper"], [class*="list"],
[class*="privateChannels"], [class*="channelList"], [class*="chat"]:not([class*="transparent"]),
[class*="messagesWrapper"], [class*="scroller"], [class*="titleBar"], [class*="header"],
[class*="modal"], [class*="popout"], [class*="tooltip"], [class*="menu"], [class*="userPopout"],
[class*="layerContainer"], [class*="settings"], [class*="activity"], [class*="embed"] {
  background-color: rgba(10, 10, 12, 0.75) !important;
  backdrop-filter: blur(2px);
}

/* ---------- 3. BUT CHAT AREA SHOULD BE MORE TRANSPARENT (better image view) ---------- */
[class*="chat"] [class*="messages"], [class*="chatContent"], [class*="scrollerInner"] {
  background-color: transparent !important;
  backdrop-filter: none;
}

/* ---------- 4. ALL TEXT: SUPER BRIGHT WHITE ---------- */
body, div, span, p, a, h1, h2, h3, h4, h5, h6, .text, .channelName, .name, .username,
.messageContent, [class*="message"], [class*="channel"], [class*="member"],
[class*="header"], [class*="title"], [class*="name"], [class*="role"], [class*="status"] {
  color: #FFFFFF !important;
  text-shadow: 0 0 1px rgba(255,255,255,0.2);
}

/* ---------- 5. LUFFY BLUE ACCENTS (Buttons, Icons, Hashtags, Links, Status) ---------- */
/* Channel hash (#) and channel icons */
[class*="icon"], [class*="channelIcon"], [class*="prefix"], [class*="hash"],
[class*="guildIcon"], [class*="voiceIcon"], [class*="activityIcon"] {
  color: #3a86ff !important;
}

/* All buttons base */
[class*="button"], [class*="clickable"], [class*="select"], [class*="option"],
[class*="item"], [class*="action"], [class*="control"] {
  transition: all 0.15s ease;
}
[class*="button"]:hover, [class*="clickable"]:hover, [class*="option"]:hover,
[class*="item"]:hover {
  filter: drop-shadow(0 0 3px #3a86ff);
}

/* Primary buttons (solid blue) */
[class*="buttonPrimary"], [class*="brand"], [class*="positive"],
[class*="lookFilled"][class*="colorBrand"], [class*="colorPrimary"] {
  background-color: #3a86ff !important;
  border-color: #3a86ff !important;
}
[class*="buttonPrimary"]:hover, [class*="brand"]:hover, [class*="positive"]:hover {
  background-color: #0050b3 !important;
}

/* Secondary / outline buttons */
[class*="buttonSecondary"], [class*="outline"], [class*="lookOutlined"][class*="colorBrand"] {
  background-color: rgba(10, 10, 12, 0.7) !important;
  border-color: #3a86ff !important;
  color: #3a86ff !important;
}
[class*="buttonSecondary"]:hover, [class*="outline"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}

/* Danger buttons (red) */
[class*="buttonDanger"], [class*="lookFilled"][class*="colorDanger"] {
  background-color: #f83838 !important;
  border-color: #f83838 !important;
}

/* ---------- 6. GOLD MENTIONS & PINGS (for contrast) ---------- */
.mention, .mention.interactive, [class*="mention"] {
  background: linear-gradient(135deg, rgba(255,184,0,0.85), rgba(255,100,0,0.6)) !important;
  color: #FFFFFF !important;
  border-radius: 8px;
  box-shadow: 0 0 8px #FFB800;
  font-weight: bold;
  padding: 2px 6px;
}
.mention:hover {
  background: rgba(255,184,0,0.95) !important;
  box-shadow: 0 0 12px #FFB800;
}

/* ---------- 7. MESSAGE HOVER & SELECTION (blue tint) ---------- */
[class*="message"]:hover, [class*="selected"], [class*="messageGroupWrapper"]:hover {
  background-color: rgba(58, 134, 255, 0.12) !important;
}

/* ---------- 8. CHAT INPUT AREA ---------- */
.textArea-2, .chatInput-3, [class*="channelTextArea"], [class*="slateContainer"] {
  background-color: rgba(10, 10, 12, 0.95) !important;
  border: 1px solid rgba(58, 134, 255, 0.5) !important;
  border-radius: 12px;
}

/* ---------- 9. SCROLLBARS (blue) ---------- */
::-webkit-scrollbar-thumb {
  background: rgba(58, 134, 255, 0.7) !important;
  border-radius: 10px;
}
::-webkit-scrollbar-track {
  background: rgba(0, 0, 0, 0.4) !important;
}
::-webkit-scrollbar-corner {
  background: rgba(0, 0, 0, 0.4) !important;
}
* {
  scrollbar-color: #3a86ff rgba(0, 0, 0, 0.4);
}

/* ---------- 10. GUILD ICONS - blue glow on hover ---------- */
[class*="guildIcon"], [class*="wrapper"], [class*="listItem"] {
  transition: transform 0.2s, filter 0.2s;
}
[class*="guildIcon"]:hover, [class*="wrapper"]:hover {
  transform: scale(1.05);
  filter: drop-shadow(0 0 6px #3a86ff);
}

/* ---------- 11. MODALS, POPOUTS, TOOLTIPS ---------- */
.modal, .popout, .tooltip, .userPopout, [class*="popover"],
[class*="menu"], [class*="dropdown"], [class*="options"],
[class*="layerContainer"] [class*="container"] {
  background-color: rgba(10, 10, 12, 0.96) !important;
  backdrop-filter: blur(6px);
  border: 1px solid rgba(58, 134, 255, 0.3);
  border-radius: 8px;
}

/* ---------- 12. INPUT FIELDS & TEXTAREAS ---------- */
input, textarea, select, [class*="input"], [class*="field"],
[class*="textArea"]:not([class*="channelTextArea"]) {
  background-color: rgba(0, 0, 0, 0.8) !important;
  color: #FFFFFF !important;
  border-color: rgba(58, 134, 255, 0.5) !important;
  border-radius: 6px;
}
input:focus, textarea:focus, select:focus {
  border-color: #3a86ff !important;
  box-shadow: 0 0 4px #3a86ff;
}

/* ---------- 13. LINKS ---------- */
a, [class*="link"], [class*="anchor"] {
  color: #3a86ff !important;
  text-decoration: none;
}
a:hover, [class*="link"]:hover {
  color: #7cb5ff !important;
  text-decoration: underline;
}

/* ---------- 14. CHANNEL LIST - blue category names, hash icons ---------- */
[class*="channelName"], [class*="categoryName"], [class*="nameDefaultText"] {
  color: #FFFFFF !important;
}
[class*="channelName"]:hover, [class*="categoryName"]:hover {
  color: #3a86ff !important;
}
[class*="icon"][class*="hash"], [class*="prefix"] {
  color: #3a86ff !important;
}

/* ---------- 15. MEMBER LIST & ACTIVITY ---------- */
[class*="member"]:hover, [class*="activity"] {
  background-color: rgba(58, 134, 255, 0.1) !important;
}
[class*="avatar"]:hover {
  filter: drop-shadow(0 0 4px #3a86ff);
}

/* ---------- 16. STATUS INDICATORS (blue online) ---------- */
[class*="statusOnline"], [class*="statusStreaming"] {
  background-color: #3a86ff !important;
}
[class*="statusIdle"] {
  background-color: #faeb64 !important;
}
[class*="statusDND"] {
  background-color: #f83838 !important;
}
[class*="statusOffline"] {
  background-color: #AAAAAA !important;
}

/* ---------- 17. REACTION BUTTONS ---------- */
[class*="reaction"], [class*="reactionInner"] {
  background-color: rgba(0, 0, 0, 0.5) !important;
  border-color: rgba(58, 134, 255, 0.3) !important;
}
[class*="reaction"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
  border-color: #3a86ff !important;
}

/* ---------- 18. CONTEXT MENUS ---------- */
[class*="contextMenu"] [class*="item"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}
[class*="contextMenu"] [class*="dangerItem"]:hover {
  background-color: rgba(248, 56, 56, 0.2) !important;
}

/* ---------- 19. EMBEDS & ATTACHMENTS ---------- */
[class*="embed"], [class*="attachment"] {
  background-color: rgba(0, 0, 0, 0.75) !important;
  border-left: 4px solid #3a86ff !important;
  border-radius: 8px;
}
[class*="embedTitle"] {
  color: #3a86ff !important;
}

/* ---------- 20. TOAST NOTIFICATIONS ---------- */
[class*="toast"], [class*="snackbar"] {
  background-color: rgba(10, 10, 12, 0.95) !important;
  border: 1px solid #3a86ff;
}

/* ---------- 21. VOICE CHANNEL CONTROLS ---------- */
[class*="voiceUser"]:hover, [class*="voiceChannel"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}
[class*="voiceState"] [class*="button"]:hover {
  color: #3a86ff !important;
}

/* ---------- 22. SPOILER TAGS ---------- */
[class*="spoilerHidden"] {
  background-color: rgba(0, 0, 0, 0.8) !important;
}
[class*="spoilerRevealed"] {
  background-color: rgba(40, 40, 45, 0.7) !important;
}

/* ---------- 23. MESSAGE ACTION BUTTONS ---------- */
[class*="messageActions"] [class*="button"] {
  background-color: rgba(0, 0, 0, 0.7) !important;
  border-radius: 4px;
}
[class*="messageActions"] [class*="button"]:hover {
  background-color: #3a86ff !important;
}

/* ---------- 24. CALL / VIDEO CONTROLS ---------- */
[class*="callContainer"] [class*="button"]:hover {
  background-color: #3a86ff !important;
}

/* ---------- 25. DISCOVERY & SHOP ---------- */
[class*="guildsDiscovery"], [class*="shop"] {
  background-color: rgba(0, 0, 0, 0.85) !important;
}

/* ---------- 26. TYPING INDICATOR (blue pulse) ---------- */
[class*="typing"] {
  color: #3a86ff !important;
}
[class*="typingDots"] {
  background-color: #3a86ff !important;
}

/* ---------- 27. BADGES (unread, mentions) ---------- */
[class*="badge"], [class*="unread"], [class*="mentionBadge"] {
  background-color: #3a86ff !important;
  color: white !important;
}
[class*="unread"] {
  background-color: #3a86ff !important;
}

/* ---------- 28. SEARCH BAR ---------- */
[class*="searchBar"] {
  background-color: rgba(0, 0, 0, 0.8) !important;
  border: 1px solid rgba(58, 134, 255, 0.5) !important;
}
[class*="searchBar"]:focus-within {
  border-color: #3a86ff !important;
}

/* ---------- 29. USER SETTINGS MODAL ---------- */
[class*="standardSidebarView"] {
  background-color: rgba(0, 0, 0, 0.9) !important;
}
[class*="settingsTab"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}
[class*="settingsTab"][class*="selected"] {
  background-color: #3a86ff !important;
  color: white !important;
}

/* ---------- 30. NOTIFICATION POPUPS ---------- */
[class*="notification"] {
  background-color: rgba(10, 10, 12, 0.95) !important;
  border-left: 4px solid #3a86ff;
}

/* ---------- 31. SELECT MENU DROPDOWNS ---------- */
[class*="select"] [class*="option"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}
[class*="selectedValue"] {
  color: #3a86ff !important;
}

/* ---------- 32. DATE SEPARATORS IN CHAT ---------- */
[class*="divider"] span {
  background-color: rgba(0, 0, 0, 0.6) !important;
  color: #3a86ff !important;
}

/* ---------- 33. LOADING SPINNERS ---------- */
[class*="spinner"] circle {
  stroke: #3a86ff !important;
}

/* ---------- 34. INVITE BUTTON ---------- */
[class*="inviteButton"] {
  background-color: #3a86ff !important;
}
[class*="inviteButton"]:hover {
  background-color: #0050b3 !important;
}

/* ---------- 35. FRIENDS LIST & DM LIST ---------- */
[class*="friendsTable"], [class*="peopleList"] {
  background-color: rgba(0, 0, 0, 0.6) !important;
}
[class*="friend"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}

/* ---------- 36. STAGE CHANNELS ---------- */
[class*="stage"] [class*="speaker"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}

/* ---------- 37. THREADS ---------- */
[class*="threadIcon"] {
  color: #3a86ff !important;
}
[class*="thread"]:hover {
  background-color: rgba(58, 134, 255, 0.1) !important;
}

/* ---------- 38. QUICK SWITCHER (Ctrl+K) ---------- */
[class*="quickswitcher"] {
  background-color: rgba(0, 0, 0, 0.9) !important;
  border: 1px solid #3a86ff;
}
[class*="result"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}

/* ---------- 39. ROLE PILLS ---------- */
[class*="rolePill"] {
  background-color: rgba(58, 134, 255, 0.2) !important;
  border: 1px solid #3a86ff;
}

/* ---------- 40. FINAL SAFETY: ENSURE NOTHING IS INVISIBLE ---------- */
* {
  opacity: 1 !important;
  visibility: visible !important;
}
